/**
 * Request logger middleware.
 * Logs: METHOD  path  statusCode  Xms
 */
function logger(req, res, next) {
  const start = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - start;
    console.log(`${req.method}  ${req.path}  ${res.statusCode}  ${duration}ms`);
  });

  next();
}

module.exports = logger;

/**
 * Centralised error-handling middleware.
 * Must be registered last (after all routes) so Express routes errors here.
 *
 * Responds with a consistent JSON shape:
 *   { error: { message, status, ...(stack in development) } }
 */
// eslint-disable-next-line no-unused-vars
function errorHandler(err, req, res, next) {
  const status = err.status || err.statusCode || 500;
  const message = err.message || 'Internal Server Error';

  const body = { error: { message, status } };

  if (process.env.NODE_ENV !== 'production') {
    body.error.stack = err.stack;
  }

  res.status(status).json(body);
}

module.exports = errorHandler;

